import java.util.*;

public class Solution {
    public static long solve(long n, long[][] edges, String label) {
        int nInt = (int) n;
        List<List<Integer>> adj = new ArrayList<>();
        for (int i = 0; i < nInt; i++) {
            adj.add(new ArrayList<>());
        }
        for (int i = 0; i < edges.length; i++) {
            int u = (int) edges[i][0];
            int v = (int) edges[i][1];
            adj.get(u).add(v);
            adj.get(v).add(u);
        }

        long[] maxLen = new long[1];
        maxLen[0] = 1;
        for (int start = 0; start < nInt; start++) {
            long visited = 1 << start;
            List<Character> path = new ArrayList<>();
            path.add(label.charAt(start));
            dfs(start, visited, path, adj, label, maxLen);
        }
        return maxLen[0];
    }

    private static void dfs(int current, long visited, List<Character> path, List<List<Integer>> adj, String label, long[] maxLen) {
        if (isPalindrome(path)) {
            maxLen[0] = Math.max(maxLen[0], (long) path.size());
        }
        for (int neighbor : adj.get(current)) {
            if ((visited & (1 << neighbor)) == 0) {
                path.add(label.charAt(neighbor));
                visited |= (1 << neighbor);
                dfs(neighbor, visited, path, adj, label, maxLen);
                path.remove(path.size() - 1);
                visited ^= (1 << neighbor);
            }
        }
    }

    private static boolean isPalindrome(List<Character> path) {
        int left = 0;
        int right = path.size() - 1;
        while (left < right) {
            if (path.get(left) != path.get(right)) {
                return false;
            }
            left++;
            right--;
        }
        return true;
    }
}
